Install:
claude mcp add kubernetes --env KUBECONFIG=/path/to/your/kubeconfig -- uvx mcp-kubernetes-server && claude mcp list

Config:
{
  "kubernetes": {
    "env": {
      "KUBECONFIG": "${KUBECONFIG:-~/.kube/config}"
    },
    "args": [
      "mcp-kubernetes-server"
    ],
    "command": "uvx"
  }
}

Usage:
{
  "kubernetes": {
    "env": {
      "KUBECONFIG": "${KUBECONFIG:-~/.kube/config}"
    },
    "args": [
      "mcp-kubernetes-server"
    ],
    "command": "uvx"
  }
}
